import java.io.IOException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSProtectedServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        String safeOutput = "";

        try {
            safeOutput = "<p>User Input: " + ESAPI.encoder().encodeForHTML(userInput) + "</p>";
        } catch (EncodingException e) {
            // Handle encoding exception
            safeOutput = "<p>Error processing input</p>";
        }

        response.getWriter().write(safeOutput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
